#include "biblia.h"

void Biblia::CarregarNeemias(Biblia* b) {
    b->dados[NEEMIAS].nome = wxT("Neemias");

    b->dados[NEEMIAS].capitulos[1].versos[1] = wxT("Palavras de Neemias, filho de Hacalias. Ora, sucedeu no mês de quisleu, no ano vigésimo, estando eu em Susã, a capital,");
    b->dados[NEEMIAS].capitulos[1].versos[2] = wxT("que veio Hanâni, um de meus irmãos, com alguns de Judá; e perguntei-lhes pelos judeus que tinham escapado e que restaram do cativeiro, e acerca de Jerusalém.");
    b->dados[NEEMIAS].capitulos[1].versos[3] = wxT("Eles me responderam: Os restantes que ficaram do cativeiro, lá na província estão em grande aflição e opróbrio; também está derribado o muro de Jerusalém, e as suas portas queimadas a fogo.");
    b->dados[NEEMIAS].capitulos[1].versos[4] = wxT("Tendo eu ouvido estas palavras, sentei-me e chorei, e lamentei por alguns dias; e continuei a jejuar e orar perante o Deus do céu,");
    b->dados[NEEMIAS].capitulos[1].versos[5] = wxT("e disse: Ó Senhor, Deus do céu, Deus grande e temível, que guardas o pacto e usas de misericórdia para com aqueles que te amam e guardam os teus mandamentos:");
    b->dados[NEEMIAS].capitulos[1].versos[6] = wxT("Estejam atentos os teus ouvidos e abertos os teus olhos, para ouvires a oração do teu servo, que eu hoje faço perante ti, dia e noite, pelos filhos de Israel, teus servos, confessando eu os pecados dos filhos de Israel, que temos cometido contra ti; sim, eu e a casa de meu pai pecamos;");
    b->dados[NEEMIAS].capitulos[1].versos[7] = wxT("na verdade temos procedido perversamente contra ti, e não temos guardado os mandamentos, nem os estatutos, nem os juízos, que ordenaste a teu servo Moisés.");
    b->dados[NEEMIAS].capitulos[1].versos[8] = wxT("Lembra-te, pois, da palavra que ordenaste a teu servo Moisés, dizendo: Se vós transgredirdes, eu vos espalharei por entre os povos;");
    b->dados[NEEMIAS].capitulos[1].versos[9] = wxT("mas se vos converterdes a mim, e guardardes os meus mandamentos e os cumprirdes, ainda que os vossos rejeitados estejam na extremidade do céu, de lá os ajuntarei e os trarei para o lugar que tenho escolhido para ali fazer habitar o meu nome.");
    b->dados[NEEMIAS].capitulos[1].versos[10] = wxT("Eles são os teus servos e o teu povo, que resgataste com o teu grande poder e com a tua mão poderosa.");
    b->dados[NEEMIAS].capitulos[1].versos[11] = wxT("Ó Senhor, que estejam atentos os teus ouvidos à oração do teu servo, e à oração dos teus servos que se deleitam em temer o teu nome; e faze prosperar hoje o teu servo, e dá-lhe graça perante este homem. {Era eu então copeiro do rei.}");

    b->dados[NEEMIAS].capitulos[2].versos[1] = wxT("Sucedeu, pois, no mês de nisã, no ano vigésimos do rei Artaxerxes, quando o vinho estava posto diante dele, que eu apanhei o vinho e o dei ao rei. Ora, eu nunca estivera triste na sua presença.");
    b->dados[NEEMIAS].capitulos[2].versos[2] = wxT("E o rei me disse: Por que está triste o teu rosto, visto que não estás doente? Não é isto senão tristeza de coração. Então temi sobremaneira.");
    b->dados[NEEMIAS].capitulos[2].versos[3] = wxT("e disse ao rei: Viva o rei para sempre! Como não há de estar triste o meu rosto, estando na cidade, o lugar dos sepulcros de meus pais, assolada, e tendo sido consumidas as suas portas pelo fogo?");
    b->dados[NEEMIAS].capitulos[2].versos[4] = wxT("Então o rei me perguntou: Que me pedes agora? Orei, pois, ao Deus do céu,");
    b->dados[NEEMIAS].capitulos[2].versos[5] = wxT("e disse ao rei: Se for do agrado do rei, e se teu servo tiver achado graça diante de ti, peço-te que me envies a Judá, à cidade dos sepulcros de meus pais, para que eu a reedifique.");
    b->dados[NEEMIAS].capitulos[2].versos[6] = wxT("Então o rei, estando a rainha assentada junto a ele, me disse: Quanto durará a tua viagem, e quando voltarás? E aprouve ao rei enviar-me, apontando-lhe eu certo prazo.");
    b->dados[NEEMIAS].capitulos[2].versos[7] = wxT("Eu disse ainda ao rei: Se for do agrado do rei, dêem-se-me cartas para os governadores dalém do Rio, para que me permitam passar até que eu chegue a Judá;");
    b->dados[NEEMIAS].capitulos[2].versos[8] = wxT("como também uma carta para Asafe, guarda da floresta do rei, a fim de que me dê madeira para as vigas das portas do castelo que pertence à casa, e para o muro da cidade, e para a casa que eu houver de ocupar. E o rei mas deu, graças à mão benéfica do meu Deus sobre mim.");
    b->dados[NEEMIAS].capitulos[2].versos[9] = wxT("Então fui ter com os governadores dalém do Rio, e lhes entreguei as cartas do rei. Ora, o rei tinha enviado comigo oficiais do exército e cavaleiros.");
    b->dados[NEEMIAS].capitulos[2].versos[10] = wxT("O que ouvindo Sambalate, o horonita, e Tobias, o servo amonita, ficaram extremamente agastados de que alguém viesse a procurar o bem dos filhos de Israel.");
    b->dados[NEEMIAS].capitulos[2].versos[11] = wxT("Cheguei, pois, a Jerusalém, e estive ali três dias.");
    b->dados[NEEMIAS].capitulos[2].versos[12] = wxT("Então de noite me levantei, eu e uns poucos homens comigo; e não declarei a ninguém o que o meu deus pusera no coração para fazer por Jerusalém. Não havia comigo animal algum, senão aquele que eu montava.");
    b->dados[NEEMIAS].capitulos[2].versos[13] = wxT("Assim saí de noite pela porta do vale, até a fonte do dragão, e até a porta do monturo, e contemplei os muros de Jerusalém, que estavam demolidos, e as suas portas, que tinham sido consumidas pelo fogo.");
    b->dados[NEEMIAS].capitulos[2].versos[14] = wxT("E passei adiante até a porta da fonte, e à piscina do rei; porém não havia lugar por onde pudesse passar o animal que eu montava.");
    b->dados[NEEMIAS].capitulos[2].versos[15] = wxT("Ainda de noite subi pelo ribeiro, e contemplei o muro; e virando, entrei pela porta do vale, e assim voltei.");
    b->dados[NEEMIAS].capitulos[2].versos[16] = wxT("E não souberam os magistrados aonde eu fora nem o que eu fazia; pois até então eu não havia declarado coisa alguma, nem aos judeus, nem aos sacerdotes, nem aos nobres, nem aos magistrados, nem aos demais que faziam a obra.");
    b->dados[NEEMIAS].capitulos[2].versos[17] = wxT("Então eu lhes disse: Bem vedes vós o triste estado em que estamos, como Jerusalém está assolada, e as suas portas queimadas a fogo; vinde, pois, e edifiquemos o muro de Jerusalém, para que não estejamos mais em opróbrio.");
    b->dados[NEEMIAS].capitulos[2].versos[18] = wxT("Então lhes declarei como a mão do meu Deus me fora favorável, e bem assim as palavras que o rei me tinha dito. Eles disseram: Levantemo-nos, e edifiquemos. E fortaleceram as mãos para a boa obra.");
    b->dados[NEEMIAS].capitulos[2].versos[19] = wxT("O que ouvindo Sambalate, o horonita, e Tobias, o servo amonita, e Gesem, o arábio, zombaram de nós, desprezaram-nos e disseram: O que é isso que fazeis? Quereis rebelar-vos contra o rei?");
    b->dados[NEEMIAS].capitulos[2].versos[20] = wxT("Então lhes respondi: O Deus do céu é que nos fará prosperar; e nós, seus servos, nos levantaremos e edificaremos: mas vós não tendes parte, nem direito, nem memorial em Jerusalém.");

    b->dados[NEEMIAS].capitulos[3].versos[1] = wxT("Então se levantou Eliasibe, o sumo sacerdote, juntamente com os seus irmãos, os sacerdotes, e edificaram a porta das ovelhas, a qual consagraram, e lhe assentaram os batentes. Consagraram-na até a torre dos cem, até a torre de Henanel.");
    b->dados[NEEMIAS].capitulos[3].versos[2] = wxT("E junto a ele edificaram os homens de Jericó; também ao lado destes edificou Zacur, o filho de Inri.");
    b->dados[NEEMIAS].capitulos[3].versos[3] = wxT("Os filhos de Hassenaá edificaram a porta dos peixes, colocaram-lhe as vigas, e lhe assentaram os batentes, com seus ferrolhos e trancas.");
    b->dados[NEEMIAS].capitulos[3].versos[4] = wxT("Ao seu lado fez os reparos Meremote, filho de Urias, filho de Hacoz; ao seu lado Mesulão, filho de Berequias, filho de Mesezabel; ao seu lado Zadoque, filho de Baaná;");
    b->dados[NEEMIAS].capitulos[3].versos[5] = wxT("ao lado destes repararam os tecoítas; porém os seus nobres não meteram o pescoço os serviço do Senhor.");
    b->dados[NEEMIAS].capitulos[3].versos[6] = wxT("Joiada, filho de Paséia, e Mesulão, filho de Besodéias, repararam a porta velha, colocaram-lhe as vigas, e lhe assentaram os batentes com seus ferrolhos e trancas.");
    b->dados[NEEMIAS].capitulos[3].versos[7] = wxT("Junto deles fizeram os reparos Melatias, o gibeonita, e Jadom, o meronotita, homens de Gibeão e de Mizpá, que pertenciam ao domínio do governador dalém do Rio;");
    b->dados[NEEMIAS].capitulos[3].versos[8] = wxT("ao seu lado Uziel, filho de Haraías, um dos ourives; ao lado dele Hananias, um dos perfumistas; e fortificaram Jerusalém até o muro largo.");
    b->dados[NEEMIAS].capitulos[3].versos[9] = wxT("Ao seu lado fez os reparos Refaías, filho de Hur, governador da metade do distrito de Jerusalém;");
    b->dados[NEEMIAS].capitulos[3].versos[10] = wxT("ao seu lado Jedaías, filho de Harumafe, defronte de sua casa; ao seu lado Hatus, filho de Hasabnéias.");
    b->dados[NEEMIAS].capitulos[3].versos[11] = wxT("Malquias, filho de Harim, e Hassube, filho de Paate-Moabe, repararam outra parte, como também a torre dos fornos;");
    b->dados[NEEMIAS].capitulos[3].versos[12] = wxT("e ao seu lado Salum, filho de Haloés, governador da outra metade do distrito de Jerusalém, ele e as suas filhas.");
    b->dados[NEEMIAS].capitulos[3].versos[13] = wxT("A porta do vale, repararam-na Hanum e os moradores de Zanoa; estes a edificaram, e lhe assentaram os batentes, com seus ferrolhos e trancas, como também mil côvados de muro até a porto do monturo.");
    b->dados[NEEMIAS].capitulos[3].versos[14] = wxT("A porta do monturo, reparou-a Malquias, filho de Recabe, governador do distrito Bete-Haquerem; este a edificou, e lhe assentou os batentes com seus ferrolhos e trancas.");
    b->dados[NEEMIAS].capitulos[3].versos[15] = wxT("A porta da fonte, reparou-a Salum, filho de Col-Hoze, governador do distrito de Mizpá; edificou-a e a cobriu, e lhe assentou os batentes, com seus ferrolhos e trancas; edificou também o muro da piscina de Selá, do jardim do rei, até os degraus que descem da cidade de Davi.");
    b->dados[NEEMIAS].capitulos[3].versos[16] = wxT("Depois dele Neemias, filho de Azbuque, governador da metade do distrito de Bete-Zur, fez os reparos até defronte dos sepulcros de Davi, até a piscina artificial, e até a casa dos homens poderosos.");
    b->dados[NEEMIAS].capitulos[3].versos[17] = wxT("Depois dele fizeram os reparos os levitas: Reum, filho de Bani, e ao seu lado, Hasabias, governador da metade do distrito de Queila, por seu distrito;");
    b->dados[NEEMIAS].capitulos[3].versos[18] = wxT("depois dele seus irmãos, Bavai, filho de Henadade, governador da outra metade do distrito de Queila.");
    b->dados[NEEMIAS].capitulos[3].versos[19] = wxT("Ao seu lado Ézer, filho de Jesuá, governador de Mizpá, reparou outra parte, defronte da subida para a casa das armas, no ângulo.");
    b->dados[NEEMIAS].capitulos[3].versos[20] = wxT("Depois dele reparou Baruque, filho de Zabai, outra parte, desde o ângulo até a porta da casa de Eliasibe, o sumo sacerdote.");
    b->dados[NEEMIAS].capitulos[3].versos[21] = wxT("Depois dele reparou Meremote, filho de Urias, filho de Hacoz, outra parte, deste a porta da casa de Eliasibe até a extremidade da mesma.");
    b->dados[NEEMIAS].capitulos[3].versos[22] = wxT("Depois dele fizeram os reparos os sacerdotes que habitavam na campina;");
    b->dados[NEEMIAS].capitulos[3].versos[23] = wxT("depois Benjamim e Hassube, defronte da sua casa; depois deles Azarias, filho de Maaséias, filho de Ananias, junto à sua casa.");
    b->dados[NEEMIAS].capitulos[3].versos[24] = wxT("Depois dele reparou Binuí, filho de Henadade, outra porte, desde a casa de Azarias até o ângulo e até a esquina.");
    b->dados[NEEMIAS].capitulos[3].versos[25] = wxT("Palal, filho de Uzai, reparou defronte do ângulo, e a torre que se projeta da casa real superior, que está junto ao átrio da guarda; depois dele Pedaías, filho de Parós.");
    b->dados[NEEMIAS].capitulos[3].versos[26] = wxT("{Ora, os netinins habitavam em Ofel, até defronte da porta das águas, para o oriente, e até a torre que se projeta.}");
    b->dados[NEEMIAS].capitulos[3].versos[27] = wxT("Depois repararam os tecoítas outra parte, defronte da grande torre que se projeta, e até o muro de Ofel.");
    b->dados[NEEMIAS].capitulos[3].versos[28] = wxT("Para cima da porta dos cavalos fizeram os reparos os sacerdotes, cada um defronte da sua casa;");
    b->dados[NEEMIAS].capitulos[3].versos[29] = wxT("depois dele Zadoque, filho de Imer, defronte de sua casa; e depois dele Semaías, filho de Secanias, guarda da porta oriental.");
    b->dados[NEEMIAS].capitulos[3].versos[30] = wxT("Depois dele repararam outra parte Hananias, filho de Selemias, e Hanum, o sexto filho de Zalafe. Depois dele reparou Mesulão, filho de Berequias, uma parte defronte da sua câmara.");
    b->dados[NEEMIAS].capitulos[3].versos[31] = wxT("Depois dele reparou Malquias, um dos ourives, uma parte até a casa dos netinins e dos mercadores, defronte da porta da guarda, e até a câmara superior da esquina.");
    b->dados[NEEMIAS].capitulos[3].versos[32] = wxT("E entre a câmara da esquina e a porta das ovelhas repararam os ourives e os mercadores.");

    b->dados[NEEMIAS].capitulos[4].versos[1] = wxT("Ora, quando Sambalate ouviu que edificávamos o muro, ardeu em ira, indignou-se muito e escarneceu dos judeus;");
    b->dados[NEEMIAS].capitulos[4].versos[2] = wxT("e falou na presença de seus irmãos e do exército de Samária, dizendo: Que fazem estes fracos judeus? Fortificar-se-ão? Oferecerão sacrifícios? Acabarão a obra num só dia? Vivificarão dos montões de pó as pedras que foram queimadas?");
    b->dados[NEEMIAS].capitulos[4].versos[3] = wxT("Ora, estava ao lado dele Tobias, o amonita, que disse: Ainda que edifiquem, vindo uma raposa derrubará o seu muro de pedra.");
    b->dados[NEEMIAS].capitulos[4].versos[4] = wxT("Ouve, ó nosso Deus, pois somos tão desprezados; faze recair o opróbrio deles sobre as suas cabaças, e faze com que eles sejam um despojo numa terra de cativeiro.");
    b->dados[NEEMIAS].capitulos[4].versos[5] = wxT("Não cubras a sua iniquidade, e não se risque de diante de ti o seu pecado, pois que te provocaram à ira na presença dos edificadores.");
    b->dados[NEEMIAS].capitulos[4].versos[6] = wxT("Assim edificamos o muro; e todo o muro se completou até a metade da sua altura; porque o coração do povo se inclinava a trabalhar.");
    b->dados[NEEMIAS].capitulos[4].versos[7] = wxT("Mas, ouvindo Sambalate e Tobias, e os arábios, o amonitas e os asdoditas, que ia avante a reparação dos muros de Jerusalém e que já as brechas se começavam a fechar, iraram-se sobremodo;");
    b->dados[NEEMIAS].capitulos[4].versos[8] = wxT("e coligaram-se todos, para virem guerrear contra Jerusalém e fazer confusão ali.");
    b->dados[NEEMIAS].capitulos[4].versos[9] = wxT("Nós, porém, oramos ao nosso Deus, e pusemos guarda contra eles de dia e de noite.");
    b->dados[NEEMIAS].capitulos[4].versos[10] = wxT("Então disse Judá: Desfalecem as forças dos carregadores, e há muito escombro; não poderemos edificar o muro.");
    b->dados[NEEMIAS].capitulos[4].versos[11] = wxT("E os nossos inimigos disseram: Nada saberão nem verão, até que entremos no meio deles, e os matemos, e façamos cessar a obra.");
    b->dados[NEEMIAS].capitulos[4].versos[12] = wxT("Mas sucedeu que, vindo os judeus que habitavam entre eles, dez vezes nos disseram: De todos os lugares de onde moram subirão contra nós.");
    b->dados[NEEMIAS].capitulos[4].versos[13] = wxT("Pelo que nos lugares baixos por detrás do muro e nos lugares abertos, dispus o povo segundo suas famílias com as suas espadas, com as suas lanças, e com os seus arcos.");
    b->dados[NEEMIAS].capitulos[4].versos[14] = wxT("Olhei, levantei-me, e disse aos nobres, aos magistrados e ao resto do povo: Não os temais! Lembrai-vos do Senhor, grande e temível, e pelejai por vossos irmãos, vossos filhos, vossas filhas, vossas mulheres e vossas casas.");
    b->dados[NEEMIAS].capitulos[4].versos[15] = wxT("Quando os nossos inimigos souberam que nós tínhamos sido avisados, e que Deus tinha dissipado o conselho deles, todos voltamos ao muro, cada um para a sua obra.");
    b->dados[NEEMIAS].capitulos[4].versos[16] = wxT("Desde aquele dia metade dos meus moços trabalhavam na obra, e a outra metade empunhava as lanças, os escudos, os arcos, e as couraças; e os chefes estavam por detrás de toda a casa de Judá.");
    b->dados[NEEMIAS].capitulos[4].versos[17] = wxT("Os que estavam edificando o muro, e os carregadores que levavam as cargas, cada um com uma das mãos fazia a obra e com a outra segurava a sua arma;");
    b->dados[NEEMIAS].capitulos[4].versos[18] = wxT("e cada um dos edificadores trazia a sua espada à cinta, e assim edificavam. E o que tocava a trombeta estava no meu lado.");
    b->dados[NEEMIAS].capitulos[4].versos[19] = wxT("Disse eu aos nobres, aos magistrados e ao resto do povo: Grande e extensa é a obra, e nós estamos separados no muro, longe uns dos outros;");
    b->dados[NEEMIAS].capitulos[4].versos[20] = wxT("em qualquer lugar em que ouvirdes o som da trombeta, ali vos ajuntareis conosco. O nosso Deus pelejará por nós.");
    b->dados[NEEMIAS].capitulos[4].versos[21] = wxT("Assim trabalhávamos na obra; e metade deles empunhava as lanças desde a subida da alva até o sair das estrelas.");
    b->dados[NEEMIAS].capitulos[4].versos[22] = wxT("Também nesse tempo eu disse ao povo: Cada um com o seu moço pernoite em Jerusalém, para que de noite nos sirvam de guardas, e de dia trabalhem.");
    b->dados[NEEMIAS].capitulos[4].versos[23] = wxT("Desta maneira nem eu, nem meus irmãos, nem meus moços, nem os homens da guarda que me acompanhavam largávamos as nossas vestes; cada um ia com a arma à sua direita.");

    b->dados[NEEMIAS].capitulos[5].versos[1] = wxT("Então se levantou um grande clamor do povo e de suas mulheres contra os judeus, seus irmãos.");
    b->dados[NEEMIAS].capitulos[5].versos[2] = wxT("Pois havia alguns que diziam: Nós, nossos filhos e nossas filhas somos muitos; que se nos dê trigo, para que comamos e vivamos.");
    b->dados[NEEMIAS].capitulos[5].versos[3] = wxT("Também havia os que diziam: Estamos empenhando nossos campos, as nossas vinhas e as nossas casas, para conseguirmos trigo durante esta fome.");
    b->dados[NEEMIAS].capitulos[5].versos[4] = wxT("Havia ainda outros que diziam: Temos tomado dinheiro emprestado até para o tributo do rei sobre os nossos campos e as nossas vinhas.");
    b->dados[NEEMIAS].capitulos[5].versos[5] = wxT("Ora, a nossa carne é como a carne de nossos irmãos, e nossos filhos como os filhos deles; e eis que estamos sujeitando nossos filhos e nossas filhas para serem servos, e algumas de nossas filhas já estão reduzidas à escravidão. Não está em nosso poder evitá-lo, pois outros têm os nossos campos e as nossas vinhas.");
    b->dados[NEEMIAS].capitulos[5].versos[6] = wxT("Ouvindo eu, pois, o seu clamor, e estas palavras, muito me indignei.");
    b->dados[NEEMIAS].capitulos[5].versos[7] = wxT("Então consultei comigo mesmo; depois contendi com do nobres e com os magistrados, e disse-lhes: Estais tomando juros, cada um de seu irmão. E ajuntei contra eles uma grande assembléia.");
    b->dados[NEEMIAS].capitulos[5].versos[8] = wxT("E disse-lhes: Nós, segundo as nossas posses, temos resgatado os judeus, nossos irmãos, que foram vendidos às nações; e vós venderíeis os vossos irmãos, ou seriam vendidos a nós? Então se calaram, e não acharam o que responder.");
    b->dados[NEEMIAS].capitulos[5].versos[9] = wxT("Disse mais: Não é bom o que fazeis; porventura não devíeis andar no temor do nosso Deus, por causa do opróbrio dos povos, os nosso inimigos?");
    b->dados[NEEMIAS].capitulos[5].versos[10] = wxT("Também eu, meus irmãos e meus moços lhes temos emprestado dinheiro e trigo. Deixemos, peço-vos este ganho.");
    b->dados[NEEMIAS].capitulos[5].versos[11] = wxT("Restituí-lhes hoje os seus campos, as suas vinhas, os seus olivais e as suas casas, como também a centésima parte do dinheiro, do trigo, do mosto e do azeite, que deles tendes exigido.");
    b->dados[NEEMIAS].capitulos[5].versos[12] = wxT("Então disseram: Nós lho restituiremos, e nada lhes pediremos; faremos assim como dizes. Então, chamando os sacerdotes, fi-los jurar que fariam conforme prometeram.");
    b->dados[NEEMIAS].capitulos[5].versos[13] = wxT("Também sacudi as minhas vestes, e disse: Assim sacuda Deus da sua casa e do seu trabalho todo homem que não cumprir esta promessa; assim mesmo seja ele sacudido e despojado. E toda a congregação disse: Amém! E louvaram ao Senhor; e o povo fez conforme a sua promessa.");
    b->dados[NEEMIAS].capitulos[5].versos[14] = wxT("Além disso, desde o dia em que fui nomeado seu governador na terra de Judá, desde o ano vinte até o anos trinta e dois do rei Artaxerxes, isto é, por doze anos, nem eu nem meus irmãos comemos o pão devido ao governador.");
    b->dados[NEEMIAS].capitulos[5].versos[15] = wxT("Mas os primeiros governadores, que foram antes de mim, oprimiram o povo, e tomaram-lhe pão e vinho e, além disso, quarenta siclos de prata; e até os seus moços dominavam sobre o povo. Porém eu assim não fiz, por causa do temor de Deus.");
    b->dados[NEEMIAS].capitulos[5].versos[16] = wxT("Também eu prossegui na obra deste muro, e terra nenhuma compramos; e todos os meus moços se ajuntaram ali para a obra.");
    b->dados[NEEMIAS].capitulos[5].versos[17] = wxT("Sentavam-se à minha mesa cento e cinqüenta homens dentre os judeus e os magistrados, além dos que vinham ter conosco dentre as nações que estavam ao redor de nós.");
    b->dados[NEEMIAS].capitulos[5].versos[18] = wxT("Ora, o que se preparava para cada dia era um boi e seis ovelhas escolhidas; também se preparavam aves e, de dez em dez dias, provisão de toda qualidade de vinho. Todavia, nem por isso exigi o pão devido ao governador, porquanto a servidão deste povo era pesada.");
    b->dados[NEEMIAS].capitulos[5].versos[19] = wxT("Lembra-te de mim para teu bem, ó meu Deus, e de tudo quanto tenho feito em prol deste povo.");

    b->dados[NEEMIAS].capitulos[6].versos[1] = wxT("Quando Sambalate, Tobias e Gesem, o arábio, e o resto dos nossos inimigos souberam que eu já tinha edificado o muro e que nele já não havia brecha alguma, ainda que até este tempo não tinha posto as portas nos portais,");
    b->dados[NEEMIAS].capitulos[6].versos[2] = wxT("Sambalate e Gesem mandaram dizer-me: Vem, encontremo-nos numa das aldeias da planície de Ono. Eles, porém, intentavam fazer-me mal.");
    b->dados[NEEMIAS].capitulos[6].versos[3] = wxT("E enviei-lhes mensageiros a dizer: Estou fazendo uma grande obra, de modo que não poderei descer. Por que cessaria esta obra, enquanto eu a deixasse e fosse ter convosco?");
    b->dados[NEEMIAS].capitulos[6].versos[4] = wxT("Do mesmo modo mandaram dizer-se quatro vezes; e do mesmo modo lhes respondi.");
    b->dados[NEEMIAS].capitulos[6].versos[5] = wxT("Então Sambalate, ainda pela quinta vez, me enviou o seu moço com uma carta aberta na mão,");
    b->dados[NEEMIAS].capitulos[6].versos[6] = wxT("na qual estava escrito: Entre as nações se ouviu, e Gesem o diz, que tu e os judeus intentais revoltar-vos, e por isso tu estás edificando o muro, e segundo se diz, queres fazer-te rei deles;");
    b->dados[NEEMIAS].capitulos[6].versos[7] = wxT("e que constituíste profetas para proclamarem a respeito de ti em Jerusalém: Há rei em Judá. Ora, estas coisas chegarão aos ouvidos do rei; vem pois, agora e consultemos juntamente.");
    b->dados[NEEMIAS].capitulos[6].versos[8] = wxT("Então mandei dizer-lhe: De tudo o que dizes, coisa nenhuma sucedeu, mas tu mesmo o inventas.");
    b->dados[NEEMIAS].capitulos[6].versos[9] = wxT("Pois todos eles nos procuravam atemorizar, dizendo: As suas mãos hão de largar a obra, e não se efetuará. Mas agora, ó Deus, fortalece as minhas mãos.");
    b->dados[NEEMIAS].capitulos[6].versos[10] = wxT("Fui à casa de Semaías, filho de Delaías, filho de Meetabel, que estava em recolhimento; e disse ele: Ajuntemo-nos na casa de Deus, dentro do templo, e fechemos as suas portas, pois virão matar-te; sim, de noite virão matar-te.");
    b->dados[NEEMIAS].capitulos[6].versos[11] = wxT("Eu, porém, respondi: Um homem como eu fugiria? e quem há que, sendo tal como eu, possa entrar no templo e viver? De maneira nenhuma entrarei.");
    b->dados[NEEMIAS].capitulos[6].versos[12] = wxT("E percebi que não era Deus que o enviara; mas ele pronunciou essa profecia contra mim, porquanto Tobias e Sambalate o haviam subornado.");
    b->dados[NEEMIAS].capitulos[6].versos[13] = wxT("Eles o subornaram para me atemorizar, a fim de que eu assim fizesse, e pecasse, para que tivessem de que me infamar, e assim vituperassem.");
    b->dados[NEEMIAS].capitulos[6].versos[14] = wxT("Lembra-te, meu Deus, de Tobias e de Sambalate, conforme estas suas obras, e também da profetisa Noadias, e dos demais profetas que procuravam atemorizar-me.");
    b->dados[NEEMIAS].capitulos[6].versos[15] = wxT("Acabou-se, pois, o muro aos vinte e cinco do mês de elul, em cinqüenta e dois dias.");
    b->dados[NEEMIAS].capitulos[6].versos[16] = wxT("Quando todos os nosso inimigos souberam disso, todos os povos que havia em redor de nós temeram, e abateram-se muito em seu próprio conceito; pois perceberam que fizemos esta obra com o auxílio do nosso Deus.");
    b->dados[NEEMIAS].capitulos[6].versos[17] = wxT("Além disso, naqueles dias o nobres de Judá enviaram muitas cartas a Tobias, e as cartas de Tobias vinham para eles.");
    b->dados[NEEMIAS].capitulos[6].versos[18] = wxT("Pois muitos em Judá estavam ligados a ele por juramento, por ser ele genro de Secanias, filho de Ará, e por haver seu filho Joanã casado com a filha de Mesulão, filho de Berequias.");
    b->dados[NEEMIAS].capitulos[6].versos[19] = wxT("Também as boas ações dele contavam perante mim, e as minhas palavras transmitiam a ele. Tobias, pois, escrevia cartas para me atemorizar.");

    b->dados[NEEMIAS].capitulos[7].versos[1] = wxT("Ora, depois que o muro foi edificado, tendo eu assentado as portas, e havendo sido designados os porteiros, os cantores e os levitas,");
    b->dados[NEEMIAS].capitulos[7].versos[2] = wxT("pus Hanâni, meu irmão, e Hananias, governador do castelo, sobre Jerusalém; pois ele era homem fiel e temente a Deus, mais do que muitos;");
    b->dados[NEEMIAS].capitulos[7].versos[3] = wxT("e eu lhes disse: Não se abram as portas de Jerusalém até que o sol aqueça; e enquanto os guardas estiverem nos postos se fechem e se tranquem as portas; e designei dentre os moradores de Jerusalém guardas, cada um por seu turno, e cada um diante da sua casa.");
    b->dados[NEEMIAS].capitulos[7].versos[4] = wxT("Ora, a cidade era larga e grande, mas o povo dentro dela era pouco, e ainda as casa não estavam edificadas.");
    b->dados[NEEMIAS].capitulos[7].versos[5] = wxT("Então o meu Deus me pôs no coração que ajuntasse os nobres, os magistrados e o povo, para registrar as genealogias. E achei o livro da genealogia dos que tinham subido primeiro e achei escrito nele o seguinte:");
    b->dados[NEEMIAS].capitulos[7].versos[6] = wxT("Este são os filhos da província que subiram do cativeiro dentre os exilados, que Nabucodonosor, rei da Babilônia, transportara e que voltaram para Jerusalém e para Judá, cada um para a sua cidade,");
    b->dados[NEEMIAS].capitulos[7].versos[7] = wxT("os quais vieram com Zorobabel, Jesuá, Neemias, Azarias, Raamias, Naamâni, Mordecai, Bilsã, Misperete, Bigvai, Neum e Baaná. Este é o número dos homens do povo de Israel:");
    b->dados[NEEMIAS].capitulos[7].versos[8] = wxT("foram os filhos de Parós, dois mil cento e setenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[9] = wxT("os filhos de Sefatias, trezentos e setenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[10] = wxT("os filhos de Ará, seiscentos e cinqüenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[11] = wxT("os filhos de Paate-Moabe, dos filhos de Jesuá e de Joabe, dois mil oitocentos e dezoito;");
    b->dados[NEEMIAS].capitulos[7].versos[12] = wxT("os filhos de Elão, mil duzentos e cinqüenta e quatro;");
    b->dados[NEEMIAS].capitulos[7].versos[13] = wxT("os filhos de Zatu, oitocentos e quarenta e cinco;");
    b->dados[NEEMIAS].capitulos[7].versos[14] = wxT("os filhos de Zacai, setecentos e sessenta;");
    b->dados[NEEMIAS].capitulos[7].versos[15] = wxT("os filhos de Binuí, seiscentos e quarenta e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[16] = wxT("os filhos de Bebai, seiscentos e vinte e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[17] = wxT("os filhos de Azgade, dois mil trezentos e vinte e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[18] = wxT("os filhos de Adonicão, seiscentos e sessenta e sete;");
    b->dados[NEEMIAS].capitulos[7].versos[19] = wxT("os filhos de Bigvai, dois mil e sessenta e sete;");
    b->dados[NEEMIAS].capitulos[7].versos[20] = wxT("os filhos de Adim, seiscentos e cinqüenta e cinco;");
    b->dados[NEEMIAS].capitulos[7].versos[21] = wxT("os filhos de Ater, de Ezequias, noventa e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[22] = wxT("os filhos de Hasum, trezentos e vinte e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[23] = wxT("os filhos de Bezai, trezentos e vinte e quatro;");
    b->dados[NEEMIAS].capitulos[7].versos[24] = wxT("os filhos de Harife, cento e doze;");
    b->dados[NEEMIAS].capitulos[7].versos[25] = wxT("os filhos de Gibeão, noventa e cinco;");
    b->dados[NEEMIAS].capitulos[7].versos[26] = wxT("os filhos de Belém e de Netofá, cento e oitenta e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[27] = wxT("os homens de Anatote, cento e vinte e oito;");
    b->dados[NEEMIAS].capitulos[7].versos[28] = wxT("os homens de Bete-Azmavete, quarenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[29] = wxT("os homens de Quiriate-Jeriam, de Cefira, e de Beerote, setecentos e quarenta e três;");
    b->dados[NEEMIAS].capitulos[7].versos[30] = wxT("os homens de Ramá e Gaba, seiscentos e vinte e um;");
    b->dados[NEEMIAS].capitulos[7].versos[31] = wxT("os homens de Micmás, cento e vinte e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[32] = wxT("os homens de Betel e Ai, cento e vinte e três;");
    b->dados[NEEMIAS].capitulos[7].versos[33] = wxT("os homens do outro Nebo, cinqüenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[34] = wxT("os filhos do outro Elão, mil duzentos e cinqüenta e quatro;");
    b->dados[NEEMIAS].capitulos[7].versos[35] = wxT("os filhos de Harim, trezentos e vinte;");
    b->dados[NEEMIAS].capitulos[7].versos[36] = wxT("os filhos de Jericó, trezentos e quarenta e cinco;");
    b->dados[NEEMIAS].capitulos[7].versos[37] = wxT("os filhos de Lode, de hadide e de Ono, setecentos e vinte e um;");
    b->dados[NEEMIAS].capitulos[7].versos[38] = wxT("os filhos de Senaá, três mil novecentos e trinta.");
    b->dados[NEEMIAS].capitulos[7].versos[39] = wxT("Os sacerdotes: os filhos de Jedaías, da casa de Jesuá, novecentos e setenta e três;");
    b->dados[NEEMIAS].capitulos[7].versos[40] = wxT("os filhos de Imer, mil e cinqüenta e dois;");
    b->dados[NEEMIAS].capitulos[7].versos[41] = wxT("os filhos de Pasur, mil duzentos e quarenta e sete;");
    b->dados[NEEMIAS].capitulos[7].versos[42] = wxT("os filhos de Harim, mil e dezessete;");
    b->dados[NEEMIAS].capitulos[7].versos[43] = wxT("Os levitas: os filhos de Jesuá, de Cadmiel, dos filhos de Hodevá, setenta e quatro.");
    b->dados[NEEMIAS].capitulos[7].versos[44] = wxT("Os cantores: os filhos de Asafe, cento e quarenta e oito.");
    b->dados[NEEMIAS].capitulos[7].versos[45] = wxT("Os porteiros: os filhos de Salum, os filhos de Ater, os filhos de Talmom, os filhos de Acube, os filhos de Hatita, os filhos de Sobai, cento e trinta e oito.");
    b->dados[NEEMIAS].capitulos[7].versos[46] = wxT("Os netinis: os filhos de Ziá, os filhos de Hasufa, os filhos de Tabaote,");
    b->dados[NEEMIAS].capitulos[7].versos[47] = wxT("os filhos de Querós, os filhos de Siá, os filhos de Padom,");
    b->dados[NEEMIAS].capitulos[7].versos[48] = wxT("os filhos de Lebana, os filhos de Hagaba, os filhos de Salmai,");
    b->dados[NEEMIAS].capitulos[7].versos[49] = wxT("os filhos de Hanã, os filhos de Gidel, os filhos de Gaar,");
    b->dados[NEEMIAS].capitulos[7].versos[50] = wxT("os filhos de Recaías, os filhos de Rezim, os filhos de Necoda,");
    b->dados[NEEMIAS].capitulos[7].versos[51] = wxT("os filhos de Gazão, os filhos de Uzá, os filhos de Paséia,");
    b->dados[NEEMIAS].capitulos[7].versos[52] = wxT("os filhos de Besai, os filhos de Meunim, os filhos de Nefusesim,");
    b->dados[NEEMIAS].capitulos[7].versos[53] = wxT("os filhos de Baquebuque, os filhos de Hacufa, os filhos de Hacur,");
    b->dados[NEEMIAS].capitulos[7].versos[54] = wxT("os filhos de Bazlite, os filhos de Meída, os filhos de Harsa,");
    b->dados[NEEMIAS].capitulos[7].versos[55] = wxT("os filhos de Barcos, os filhos de Sísera, os filhos de Tamá,");
    b->dados[NEEMIAS].capitulos[7].versos[56] = wxT("os filhos de Nezias, os filhos de Hatifa,");
    b->dados[NEEMIAS].capitulos[7].versos[57] = wxT("os filhos dos servos de Salomão: os filhos de Sotai, os filhos de Soforete, os filhos de Perida,");
    b->dados[NEEMIAS].capitulos[7].versos[58] = wxT("os filhos de Jaala, os filhos de Darcom, os filhos de Gidel,");
    b->dados[NEEMIAS].capitulos[7].versos[59] = wxT("os filhos de Sefatias, os filhos de Hatil, os filhos de Paquerete-Hazebaim e os filhos de Amom.");
    b->dados[NEEMIAS].capitulos[7].versos[60] = wxT("Todos os netinins e os filhos dos servos de Salomão, eram trezentos e noventa e dois.");
    b->dados[NEEMIAS].capitulos[7].versos[61] = wxT("Estes foram os que subiram de Tel-Mela, Tel-Harsa, Querube, Adom, e Imer; porém não puderam provar que as suas casas paternas e as sua linhagem eram de Israel:");
    b->dados[NEEMIAS].capitulos[7].versos[62] = wxT("os filhos de Dalaías, os filhos de Tobias, os filhos de Necoda, seiscentos e quarenta e dois.");
    b->dados[NEEMIAS].capitulos[7].versos[63] = wxT("E dos sacerdotes: os filhos de Hobaías, os filhos Hacoz, os filhos de Barzilai, que tomara por mulher uma das filhas Barzilai, o gileadita, e que foi chamado do seu nome.");
    b->dados[NEEMIAS].capitulos[7].versos[64] = wxT("Estes buscaram o seu registro entre os arrolados nos registros genealógicos, mas não foi encontrado; pelo que, tidos por imundos, foram excluídos do sacerdócio.");
    b->dados[NEEMIAS].capitulos[7].versos[65] = wxT("E o governador lhes disse que não comesse das coisas sagradas, até que se levantasse um sacerdote com Urim e Tumim.");
    b->dados[NEEMIAS].capitulos[7].versos[66] = wxT("Toda esta congregação junta somava quarenta e dois mil trezentos e sessenta;");
    b->dados[NEEMIAS].capitulos[7].versos[67] = wxT("afora os seus servos e as suas servas, que foram sete mil trezentos e trinta e sete; e tinham duzentos e quarenta e cinco cantores e cantoras.");
    b->dados[NEEMIAS].capitulos[7].versos[68] = wxT("Os seus cavalos foram setecentos e trinta e seis; os seus mulos, duzentos e quarenta e cinco;");
    b->dados[NEEMIAS].capitulos[7].versos[69] = wxT("os seus camelos, quatrocentos e trinta e cinco; e os seus jumentos, seis mil setecentos e vinte.");
    b->dados[NEEMIAS].capitulos[7].versos[70] = wxT("Ora, alguns dos cabeças das casas paternas contribuíram para a obra. O governador deu para a tesouraria mil dários de ouro, cinqüenta bacias, e quinhentas e trinta vestes sacerdotais.");
    b->dados[NEEMIAS].capitulos[7].versos[71] = wxT("E alguns dos cabeças das casas paternas deram para a tesouraria da obra vinte mil dáricos de ouro, e duas mil e duzentas minas de prata.");
    b->dados[NEEMIAS].capitulos[7].versos[72] = wxT("O que o resto do povo deu foram vinte mil dáricos de ouro, duas mil minas de prata, e sessenta e sete vestes sacerdotais.");
    b->dados[NEEMIAS].capitulos[7].versos[73] = wxT("Os sacerdotes, os levitas, os porteiros, os cantores, alguns dentre o povo, os netinins e todo o Israel habitaram nas suas cidades. Quando chegou o sétimo mês, já se achavam os filhos de Israel nas suas cidades.");

    b->dados[NEEMIAS].capitulos[8].versos[1] = wxT("Então todo o povo se ajuntou como um só homem, na praça diante da porta das águas; e disseram a Esdras, o escriba, que trouxesse o livro da lei de Moisés, que o Senhor tinha ordenado a Israel.");
    b->dados[NEEMIAS].capitulos[8].versos[2] = wxT("E Esdras, o sacerdote, trouxe a lei perante a congregação, tanto de homens como de mulheres, e de todos os que podiam ouvir com entendimento, no primeiro dia do sétimo mês.");
    b->dados[NEEMIAS].capitulos[8].versos[3] = wxT("E leu nela diante da praça que está fronteira à porta das águas, desde a alva até o meio-dia, na presença dos homens e das mulheres, e dos que podiam entender; e os ouvidos de todo o povo estavam atentos ao livro da lei.");
    b->dados[NEEMIAS].capitulos[8].versos[4] = wxT("Esdras, o escriba, ficava em pé sobre um estrado de madeira, que fizeram para esse fim e estavam em pé junto a ele, à sua direita, Matitias, Sema, Ananías, Urias, Hilquias e Maaséias; e à sua esquerda, Pedaías, Misael, Malquias, Hasum, Hasbadana, Zacarias e Mesulão.");
    b->dados[NEEMIAS].capitulos[8].versos[5] = wxT("E Esdras abriu o livro à vista de todo o povo {pois estava acima de todo o povo}; e, abrindo-o ele, todo o povo se pôs em pé.");
    b->dados[NEEMIAS].capitulos[8].versos[6] = wxT("Então Esdras bendisse ao Senhor, o grande Deus; e todo povo, levantando as mãos, respondeu: Amém! amém! E, inclinando-se, adoraram ao Senhor, com os rostos em terra.");
    b->dados[NEEMIAS].capitulos[8].versos[7] = wxT("Também Jesuá, Bani, Serebias, Jamim, Acube; Sabetai, Hodias, Maaséias, Quelita, Azarias, Jozabade, Hanã, Pelaías e os levitas explicavam ao povo a lei; e o povo estava em pé no seu lugar.");
    b->dados[NEEMIAS].capitulos[8].versos[8] = wxT("Assim leram no livro, na lei de Deus, distintamente; e deram o sentido, de modo que se entendesse a leitura.");
    b->dados[NEEMIAS].capitulos[8].versos[9] = wxT("E Neemias, que era o governador, e Esdras, sacerdote e escriba, e os levitas que ensinavam o povo, disseram a todo o povo: Este dia é consagrado ao Senhor vosso Deus; não pranteeis nem choreis. Pois todo o povo chorava, ouvindo as palavras da lei.");
    b->dados[NEEMIAS].capitulos[8].versos[10] = wxT("Disse-lhes mais: Ide, comei as gorduras, e bebei as doçuras, e enviai porções aos que não têm nada preparado para si; porque este dia é consagrado ao nosso Senhor. Portanto não vos entristeçais, pois a alegria do Senhor é a vossa força.");
    b->dados[NEEMIAS].capitulos[8].versos[11] = wxT("Os levitas, pois, fizeram calar todo o povo, dizendo: Calai-vos, porque este dia é santo; por isso não vos entristeçais.");
    b->dados[NEEMIAS].capitulos[8].versos[12] = wxT("Então todo o povo se foi para comer e beber, e para enviar porções, e para fazer grande regozijo, porque tinha entendido as palavras que lhe foram referidas.");
    b->dados[NEEMIAS].capitulos[8].versos[13] = wxT("Ora, no dia seguinte ajuntaram-se os cabeças das casas paternas de todo o povo, os sacerdotes e os levitas, na presença de Esdras, o escriba, para examinarem as palavras da lei;");
    b->dados[NEEMIAS].capitulos[8].versos[14] = wxT("e acharam escrito na lei que o Senhor, por intermédio de Moisés, ordenara que os filhos de Israel habitassem em cabanas durante a festa do sétimo mês;");
    b->dados[NEEMIAS].capitulos[8].versos[15] = wxT("e que publicassem e fizessem passar pregão por todas as suas cidades, e em ramos de oliveiras, de zambujeiros e de murtas, folhas de palmeiras, e ramos de outras árvores frondosas, para fazerdes cabanas, como está escrito.");
    b->dados[NEEMIAS].capitulos[8].versos[16] = wxT("Saiu, pois, o povo e trouxe os ramos; e todos fizeram para si cabanas, cada um no eirado da sua casa, nos seus pátios, nos átrios da casa de Deus, na praça da porta das águas, e na praça da porta de Efraim.");
    b->dados[NEEMIAS].capitulos[8].versos[17] = wxT("E toda a comunidade dos que tinham voltado do cativeiro fez cabanas, e habitaram nelas; pois não tinham feito assim os filhos de Israel desde os dias de Josué, filho de Num, até aquele dia. E houve mui grande regozijo.");
    b->dados[NEEMIAS].capitulos[8].versos[18] = wxT("E Esdras leu no livro da lei de Deus todos os dias, desde o primeiro até o último; e celebraram a festa por sete dias, e no oitavo dia houve uma assembléia solene, segundo a ordenança.");

    b->dados[NEEMIAS].capitulos[9].versos[1] = wxT("Ora, no dia vinte e quatro desse mês, se ajuntaram os filhos de Israel em jejum, vestidos de sacos e com terra sobre as cabeças.");
    b->dados[NEEMIAS].capitulos[9].versos[2] = wxT("E os da linhagem de Israel se apartaram de todos os estrangeiros, puseram-se em pé e confessaram os seus pecados e as iniquidades de seus pais.");
    b->dados[NEEMIAS].capitulos[9].versos[3] = wxT("E, levantando-se no seu lugar, leram no livro da lei do Senhor seu Deus, uma quarta parte do dia; e outra quarta parte fizeram confissão, e adoraram ao Senhor seu Deus.");
    b->dados[NEEMIAS].capitulos[9].versos[4] = wxT("Então Jesuá, Bani, Cadmiel, Sebanias, Buni, Serebias, Bani e Quenâni se puseram em pé sobre os degraus dos levitas, e clamaram em alta voz ao Senhor seu Deus.");
    b->dados[NEEMIAS].capitulos[9].versos[5] = wxT("E os levitas Jesuá, Cadmiel, Bani, Hasabnéias, Serebias, Hodias, Sebanias e Petaías disseram: Levantai-vos, bendizei ao Senhor vosso Deus de eternidade em eternidade. Bendito seja o teu glorioso nome, que está exaltado sobre toda benção e louvor.");
    b->dados[NEEMIAS].capitulos[9].versos[6] = wxT("Tu, só tu, és Senhor; tu fizeste o céu e o céu dos céus, juntamente com todo o seu exército, a terra e tudo quanto nela existe, os mares e tudo quanto neles já, e tu os conservas a todos, e o exército do céu te adora.");
    b->dados[NEEMIAS].capitulos[9].versos[7] = wxT("Tu és o Senhor, o Deus que elegeste a Abrão, e o tiraste de Ur dos caldeus, e lhe puseste por nome Abraão;");
    b->dados[NEEMIAS].capitulos[9].versos[8] = wxT("e achaste o seu coração fiel perante ti, e fizeste com ele o pacto de que darias à sua descendência a terra dos cananeus, dos heteus, dos amorreus, dos perizeus, dos jebuseus e dos girgaseus; e tu cumpriste as tuas palavras, pois és justo.");
    b->dados[NEEMIAS].capitulos[9].versos[9] = wxT("Também viste a aflição de nossos pais no Egito, e ouviste o seu clamor junto ao Mar Vermelho;");
    b->dados[NEEMIAS].capitulos[9].versos[10] = wxT("e o operaste sinais e prodígios contra Faraó; e contra todos os seus servos, e contra todo o povo da sua terra; pois sabias com que soberba eles os haviam tratado; e assim adquiriste renome, como hoje se vê.");
    b->dados[NEEMIAS].capitulos[9].versos[11] = wxT("Fendente o mar diante deles, de modo que passaram pelo meio do mar, em seco; e lançaste os seus perseguidores nas profundezas, como uma pedra nas águas impetuosas.");
    b->dados[NEEMIAS].capitulos[9].versos[12] = wxT("Além disso tu os guiaste de dia por uma coluna de nuvem e de noite por uma coluna de fogo, para os alumiares no caminho por onde haviam de ir.");
    b->dados[NEEMIAS].capitulos[9].versos[13] = wxT("Desceste sobre o monte Sinai, do céu falaste com eles, e lhes deste juízos retos e leis verdadeiras, bons estatutos e mandamentos;");
    b->dados[NEEMIAS].capitulos[9].versos[14] = wxT("o teu santo sábado lhes fizeste conhecer; e lhes ordenaste mandamentos e estatutos e uma lei, por intermédio de teu servo Moisés.");
    b->dados[NEEMIAS].capitulos[9].versos[15] = wxT("Do céu lhes deste pão quando tiveram fome, e da rocha fizeste brotar água quando tiveram sede; e lhes ordenaste que entrassem para possuir a terra que com juramento lhes havias prometido dar.");
    b->dados[NEEMIAS].capitulos[9].versos[16] = wxT("Eles, porém, os nossos pais, se houveram soberbamente e endureceram a cerviz, e não deram ouvidos aos teus mandamentos,");
    b->dados[NEEMIAS].capitulos[9].versos[17] = wxT("recusando ouvir-te e não se lembrando das tuas maravilhas, que fizeste no meio deles; antes endureceram a cerviz e, na sua rebeldia, levantaram um chefe, a fim de voltarem para sua servidão. Tu, porém, és um Deus pronto para perdoar, clemente e misericordioso, tardio em irar-te e grande em beneficência, e não os abandonaste.");
    b->dados[NEEMIAS].capitulos[9].versos[18] = wxT("Ainda mesmo quando eles fizeram para si um bezerro de fundição, e disseram: Este é o teu Deus, que te tirou do Egito, e cometeram grandes blasfêmias,");
    b->dados[NEEMIAS].capitulos[9].versos[19] = wxT("todavia tu, pela multidão das tuas misericórdias, não os abandonaste no deserto. A coluna de nuvem não se apartou deles de dia, para os guiar pelo caminho, nem a coluna de fogo de noite, para lhes alumiar o caminho por onde haviam de ir.");
    b->dados[NEEMIAS].capitulos[9].versos[20] = wxT("Também lhes deste o teu bom espírito para os ensinar, e o teu maná não retiraste da tua boca, e água lhes deste quando tiveram sede.");
    b->dados[NEEMIAS].capitulos[9].versos[21] = wxT("Sim, por quarenta anos os sustentaste no deserto; não lhes faltou coisa alguma; a sua roupa não envelheceu, e o seus pés não se incharam.");
    b->dados[NEEMIAS].capitulos[9].versos[22] = wxT("Além disso lhes deste reinos e povos, que lhes repartiste em porções; assim eles possuíram a terra de Siom, a saber; a terra do rei de Hesbom, e a terra de Ogue, rei de Basã.");
    b->dados[NEEMIAS].capitulos[9].versos[23] = wxT("Outrossim mulplicaste os seus filhos como as estrelas do céu, e os introduziste na terra de que tinhas dito a seus pais que nela entrariam para a possuírem.");
    b->dados[NEEMIAS].capitulos[9].versos[24] = wxT("Os filhos, pois, entraram e possuíram a terra; e abateste perante eles, os moradores da terra, os cananeus, e lhos entregaste nas mãos, como também os seus reis, e os povos da terra, para fazerem deles conforme a sua vontade.");
    b->dados[NEEMIAS].capitulos[9].versos[25] = wxT("Tomaram cidades fortificadas e uma terra fértil, e possuíram casas cheias de toda sorte de coisas boas, cisternas cavadas, vinhas e olivais, e árvores frutíferas em abundância; comeram, pois, fartaram-se e engordaram, e viveram em delícias, pela tua grande bondade.");
    b->dados[NEEMIAS].capitulos[9].versos[26] = wxT("Não obstante foram desobedientes, e se rebelaram contra ti; lançaram a tua lei para trás das costas, e mataram os teus profetas que protestavam contra eles para que voltassem a ti; assim cometeram grandes provocações.");
    b->dados[NEEMIAS].capitulos[9].versos[27] = wxT("Pelo que os entregaste nas mãos dos seus adversários, que os afligiram; mas no templo da sua angústia, quando eles clamaram a ti, tu os ouviste do céu; e segundo a multidão das tuas misericórdias lhes deste libertadores que os libertaram das mãos de seus adversários.");
    b->dados[NEEMIAS].capitulos[9].versos[28] = wxT("Mas, tendo alcançado repouso, tornavam a fazer o mal diante de ti,; portanto tu os deixavas nas mãos dos seus inimigos, de modo que estes dominassem sobre eles; todavia quando eles voltavam e clamavam a ti, tu os ouvias do céu, e segundo a tua misericórdia os livraste muitas vezes;");
    b->dados[NEEMIAS].capitulos[9].versos[29] = wxT("e testemunhaste contra eles, para os fazerdes voltar para a tua lei; contudo eles se houveram soberbamente, e não deram ouvidos aos teus mandamentos, mas pecaram contra os teus juízos, pelos quais viverá o homem que os cumprir; viraram o ombro, endureceram a cerviz e não quiseram ouvir.");
    b->dados[NEEMIAS].capitulos[9].versos[30] = wxT("Não obstante, por muitos anos os aturaste, e testemunhaste contra eles pelo teu Espírito, por intermédio dos teus profetas; todavia eles não quiseram dar ouvidos; pelo que os entregaste nas mãos dos povos de outras terras.");
    b->dados[NEEMIAS].capitulos[9].versos[31] = wxT("Contudo pela tua grande misericórdia não os destruíste de todo, nem os abandonaste, porque és um Deus clemente e misericordioso.");
    b->dados[NEEMIAS].capitulos[9].versos[32] = wxT("Agora, pois, ó nosso Deus, Deus grande, poderoso e temível, que guardas o pacto e a beneficência, não tenhas em pouca conta toda a aflição que nos alcançou a nós, a nossos reis, a nossos príncipes, a nossos sacerdotes, a nossos profetas, a nossos pais e a todo o teu povo, desde os dias dos reis da Assíria até o dia de hoje.");
    b->dados[NEEMIAS].capitulos[9].versos[33] = wxT("Tu, porém, és justo em tudo quanto tem vindo sobre nós; pois tu fielmente procedeste, mas nós perversamente.");
    b->dados[NEEMIAS].capitulos[9].versos[34] = wxT("Os nossos reis, os nossos príncipes, os nossos sacerdotes, e os nossos pais não têm guardado a tua lei, nem têm dado ouvidos aos teus mandamentos e aos teus testemunhos, com que testificaste contra eles.");
    b->dados[NEEMIAS].capitulos[9].versos[35] = wxT("Porque eles, no seu reino, na muita abundância de bens que lhes deste, na terra espaçosa e fértil que puseste diante deles, não te serviram, nem se converteram de suas más obras.");
    b->dados[NEEMIAS].capitulos[9].versos[36] = wxT("Eis que hoje somo escravos; e quanto à terra que deste a nossos pais, para comerem o seu fruto e o seu bem, eis que somos escravos nela.");
    b->dados[NEEMIAS].capitulos[9].versos[37] = wxT("E ela multiplica os seus produtos para os reis que puseste sobre nós por causa dos nossos pecados; também eles dominam sobre os nossos corpos e sobre o nosso gado como bem lhes apraz, e estamos em grande angústia.");
    b->dados[NEEMIAS].capitulos[9].versos[38] = wxT("Contudo, por causa de tudo isso firmamos um pacto e o escrevemos; e selam-no os nossos príncipes, os nossos levitas e os nossos sacerdotes.");

    b->dados[NEEMIAS].capitulos[10].versos[1] = wxT("Os que selaram foram: Neemias, o governador, filho de Hacalias, Zedequias,");
    b->dados[NEEMIAS].capitulos[10].versos[2] = wxT("Seraías, Azarias, Jeremias,");
    b->dados[NEEMIAS].capitulos[10].versos[3] = wxT("Pasur, Amarias, Malquias,");
    b->dados[NEEMIAS].capitulos[10].versos[4] = wxT("Hatus, Sebanias, Maluque,");
    b->dados[NEEMIAS].capitulos[10].versos[5] = wxT("Harim, Meremote, Obadias,");
    b->dados[NEEMIAS].capitulos[10].versos[6] = wxT("Daniel, Ginetom, Baruque,");
    b->dados[NEEMIAS].capitulos[10].versos[7] = wxT("Mesulão, Abias, Miamim,");
    b->dados[NEEMIAS].capitulos[10].versos[8] = wxT("Maazias, Bilgai e Semaías; estes foram os sacerdotes.");
    b->dados[NEEMIAS].capitulos[10].versos[9] = wxT("E os levitas: Jesuá, filho de Azanias, Binuí, dos filhos de Henadade, Cadmiel,");
    b->dados[NEEMIAS].capitulos[10].versos[10] = wxT("e seus irmãos, Sebanias, Hodias, Quelita, Pelaías, Hanã,");
    b->dados[NEEMIAS].capitulos[10].versos[11] = wxT("Mica, Reobe, Hasabias,");
    b->dados[NEEMIAS].capitulos[10].versos[12] = wxT("Zacur, Serebias, Sebanias,");
    b->dados[NEEMIAS].capitulos[10].versos[13] = wxT("Hodias, Bani e Benínu.");
    b->dados[NEEMIAS].capitulos[10].versos[14] = wxT("Os chefes do povo: Parós, Paate-Moabe, Elão, Zatu, Bani,");
    b->dados[NEEMIAS].capitulos[10].versos[15] = wxT("Buni, Azgade, Bebai,");
    b->dados[NEEMIAS].capitulos[10].versos[16] = wxT("Adonias, Bigvai, Adim,");
    b->dados[NEEMIAS].capitulos[10].versos[17] = wxT("Ater, Ezequias, Azur,");
    b->dados[NEEMIAS].capitulos[10].versos[18] = wxT("Hodias, Asum, Bezai,");
    b->dados[NEEMIAS].capitulos[10].versos[19] = wxT("Harife, Anotote, Nobai,");
    b->dados[NEEMIAS].capitulos[10].versos[20] = wxT("Magpias, Mesulão, Hezir,");
    b->dados[NEEMIAS].capitulos[10].versos[21] = wxT("Mesezabel, Zadoque, Jadua,");
    b->dados[NEEMIAS].capitulos[10].versos[22] = wxT("Pelatias, Hanã, Anaías,");
    b->dados[NEEMIAS].capitulos[10].versos[23] = wxT("Oséias, Hananias, Ananías,");
    b->dados[NEEMIAS].capitulos[10].versos[24] = wxT("Haloés, Pilá, Sobeque,");
    b->dados[NEEMIAS].capitulos[10].versos[25] = wxT("Reum, Hasabna, Maaséias,");
    b->dados[NEEMIAS].capitulos[10].versos[26] = wxT("Aías, Hanã, Anã,");
    b->dados[NEEMIAS].capitulos[10].versos[27] = wxT("Maluque, Harim e Baaná.");
    b->dados[NEEMIAS].capitulos[10].versos[28] = wxT("E o resto do povo, os sacerdotes, os porteiros, os cantores, os netinins, e todos os que se tinham separado dos povos de outras terras para seguir a lei de Deus, suas mulheres, seus filhos e suas filhas, todos os que tinham conhecimento e entendimento,");
    b->dados[NEEMIAS].capitulos[10].versos[29] = wxT("aderiram a seus irmãos, os seus nobres, e convieram num juramento sob pena de maldição de que andariam na lei de Deus, a qual foi dada por intermédio de Moisés, servo de Deus, e de que guardariam e cumpririam todos os mandamentos do Senhor, nosso Senhor, e os seus juízos e os seus estatutos;");
    b->dados[NEEMIAS].capitulos[10].versos[30] = wxT("de que não daríamos as nossas filhas aos povos da terra, nem tomaríamos as filhas deles para os nossos filhos;");
    b->dados[NEEMIAS].capitulos[10].versos[31] = wxT("de que, se os povos da terra trouxessem no dia de sábado qualquer mercadoria ou quaisquer cereais para venderem, nada lhes compraríamos no sábado, nem em dia santificado; e de que abriríamos mão do produto do sétimo ano e da cobrança nele de todas as dívidas.");
    b->dados[NEEMIAS].capitulos[10].versos[32] = wxT("Também sobre nós impusemos ordenanças, obrigando-nos a dar a cada ano a terça parte dum siclo para o serviço da casa do nosso Deus;");
    b->dados[NEEMIAS].capitulos[10].versos[33] = wxT("para os pães da proposição, para a contínua oferta de cereais, para o contínuo holocausto dos sábados e das luas novas, para as festas fixas, para as coisas sagradas, para as ofertas pelo pecado a fim de fazer expiação por Israel, e para toda a obra da casa do nosso Deus.");
    b->dados[NEEMIAS].capitulos[10].versos[34] = wxT("E nós, os sacerdotes, os levitas e o povo lançamos sortes acerca da oferta da lenha que havíamos de trazer à casa do nosso Deus, segundo as nossas casas paternas, a tempos determinados, de ano em ano, para se queimar sobre o altar do Senhor nosso Deus, como está escrito na lei.");
    b->dados[NEEMIAS].capitulos[10].versos[35] = wxT("Também nos obrigamos a trazer de ano em ano à casa do Senhor as primícias de todos os frutos de todas as árvores;");
    b->dados[NEEMIAS].capitulos[10].versos[36] = wxT("e a trazer os primogênitos dos nossos filhos, e os do nosso gado, como está escrito na lei, e os primogênitos das nossas manadas e dos nossos rebanhos à casa do nosso Deus, aos sacerdotes que ministram na casa do nosso Deus;");
    b->dados[NEEMIAS].capitulos[10].versos[37] = wxT("e as primícias da nossa mas, e as nossas ofertas alçadas, e o fruto de toda sorte de árvores, para as câmaras da casa de nosso Deus; e os dízimos da nossa terra aos levitas; pois eles, os levitas, recebem os dízimos em todas as cidades por onde temos lavoura.");
    b->dados[NEEMIAS].capitulos[10].versos[38] = wxT("E o sacerdote, filho de Arão, deve estar com os levitas quando estes receberem os dízimos; e os levitas devem trazer o dízimo dos dízimos à casa do nosso Deus, para as câmaras, dentro da tesouraria.");
    b->dados[NEEMIAS].capitulos[10].versos[39] = wxT("Pois os filhos de Israel e os filhos de Levi devem trazer ofertas alçadas dos cereais, do mosto e do azeite para aquelas câmaras, em que estão os utensílios do santuário, como também os sacerdotes que ministram, e os porteiros, e os cantores; e assim não negligenciarmos a casa do nosso Deus.");

    b->dados[NEEMIAS].capitulos[11].versos[1] = wxT("Ora, os príncipes do povo habitaram em Jerusalém; e o restante do povo lançou sortes, para atirar um de cada dez que habitasse na santa cidade de Jerusalém, ficando nove nas outras cidades.");
    b->dados[NEEMIAS].capitulos[11].versos[2] = wxT("E o povo bendisse todos os homens que voluntariamente se ofereceram para habitar em Jerusalém.");
    b->dados[NEEMIAS].capitulos[11].versos[3] = wxT("Estes, pois, são os chefes da província que habitaram em Jerusalém; porém nas cidades de Judá habitou cada um na sua possessão, nas suas cidades, a saber, Israel, os sacerdotes, os levitas, os netinins e os filhos dos servos de Salomão.");
    b->dados[NEEMIAS].capitulos[11].versos[4] = wxT("E habitaram em Jerusalém alguns dos filhos de Judá e dos filhos de Benjamim. Dos filhos de Judá: Ataías, filho de Uzias, filho de Zacarias, filho de Amarias, filho de Sefatias, filho de Maalelel, dos filhos de Pérez;");
    b->dados[NEEMIAS].capitulos[11].versos[5] = wxT("e Maaséias, filho de Baruque, filho de Col-Hoze, filho de Hazaías, filho de Adaías, filho de Joiaribe, filho de Zacarias, filho de Silôni.");
    b->dados[NEEMIAS].capitulos[11].versos[6] = wxT("Todos os filhos de Pérez que habitaram em Jerusalém foram quatrocentos e sessenta e oito homens valentes.");
    b->dados[NEEMIAS].capitulos[11].versos[7] = wxT("São estes os filhos de Benjamim: Salu, filho de Mesulão, filho de Joede, filho de Pedaías, filho de Colaías, filho de Maaséias, filho de Itiel, filho de Jesaías.");
    b->dados[NEEMIAS].capitulos[11].versos[8] = wxT("E depois dele Gabai, Salai, ...novecentos e vinte e oito.");
    b->dados[NEEMIAS].capitulos[11].versos[9] = wxT("Joel, filho de Zicri, superintendente sobre eles; e Judá, filho de Senua, o segundo sobre a cidade.");
    b->dados[NEEMIAS].capitulos[11].versos[10] = wxT("Dos sacerdotes: Jedaías, filho de Joiaribe, Jaquim,");
    b->dados[NEEMIAS].capitulos[11].versos[11] = wxT("Seraías, filho de Hilquias, filho de Mesulão, filho de Zadoque, filho de Meraiote, filho de Altube, príncipe sobre a casa de Deus;");
    b->dados[NEEMIAS].capitulos[11].versos[12] = wxT("e seus irmãos que faziam a obra da casa, oitocentos e vinte e dois; e Adaías, filho de Jeroão, filho de Pelalias, filho de Anzi, filho de Zacarias, filha de Pasur, filho de Malquias,");
    b->dados[NEEMIAS].capitulos[11].versos[13] = wxT("e seus irmãos, cabeças de casas paternas, duzentos e quarenta e dois; e Amassai, filho de Azarel, filho de Aazai, filho de Mesilemote, filho de Imer,");
    b->dados[NEEMIAS].capitulos[11].versos[14] = wxT("e os irmãos deles, homens valentes, cento e vinte e oito; e o superintendente sobre eles era Zabdiel, filho de Hagedolim.");
    b->dados[NEEMIAS].capitulos[11].versos[15] = wxT("Dos levitas: Semaías, filho de Hassube, filho de Azricão, filho de Hasabias, filho de Buni;");
    b->dados[NEEMIAS].capitulos[11].versos[16] = wxT("Sabetai e Jozabade, dos cabeças dos levitas, presidiam o serviço externo da casa de Deus;");
    b->dados[NEEMIAS].capitulos[11].versos[17] = wxT("Matanias, filho de Mica, filho de Zabdi, filho de Asafe, o dirigente que iniciava as ações de graças na oração, e Baquebuquias, o segundo entre seus irmãos; depois Abda, filho de Samua, filho de Galal, filho de Jedútun.");
    b->dados[NEEMIAS].capitulos[11].versos[18] = wxT("Todos os levitas na santa cidade foram duzentos e oitenta e quatro.");
    b->dados[NEEMIAS].capitulos[11].versos[19] = wxT("Também os porteiros, Acube, Talmom, e seus irmãos, os guardas das portas, foram cento e sessenta e dois.");
    b->dados[NEEMIAS].capitulos[11].versos[20] = wxT("O resto de Israel e dos sacerdotes e levitas, habitou em todas as cidades de Judá, cada um na sua herança.");
    b->dados[NEEMIAS].capitulos[11].versos[21] = wxT("Os netinins, porém, habitaram em Ofel; e Ziá e Gispa presidiram sobre eles.");
    b->dados[NEEMIAS].capitulos[11].versos[22] = wxT("O superintendente dos levitas em Jerusalém era Uzi, filho de Bani, filho de Hasabias, filho de Matanias, filho de Mica, dos filhos de Asafe, os cantores; ele estava encarregado do serviço da casa de Deus.");
    b->dados[NEEMIAS].capitulos[11].versos[23] = wxT("Pois havia uma ordem da parte do rei acerca deles, e uma norma para os cantores, estabelecendo o dever de cada dia.");
    b->dados[NEEMIAS].capitulos[11].versos[24] = wxT("E Petaías, filho de Mesezabel, dos filhos de Zerá, filho de Judá, estava às ordens do rei, em todos os negócios concernentes ao povo.");
    b->dados[NEEMIAS].capitulos[11].versos[25] = wxT("E quanto às aldeias com os seus campos, alguns dos filhos de Judá habitaram em Quiriate-Arba e seus arrabaldes, em Dibom e seus arrabaldes, e em Jecabzeel e suas aldeias;");
    b->dados[NEEMIAS].capitulos[11].versos[26] = wxT("em Jesuá, em Molada, em Bete-Pelete,");
    b->dados[NEEMIAS].capitulos[11].versos[27] = wxT("Em Hazar-Sual, em Berseba e seus arrabaldes,");
    b->dados[NEEMIAS].capitulos[11].versos[28] = wxT("em Ziclague, em Mecona e seus arrabaldes,");
    b->dados[NEEMIAS].capitulos[11].versos[29] = wxT("em En-Rimom, em Zorá, em Jarmute,");
    b->dados[NEEMIAS].capitulos[11].versos[30] = wxT("em Zanoa, em Adulão e suas aldeias, em Laquis e seus campos, e em Azeca e seus arrabaldes. Acamparam-se, pois, desde Berseba até o vale do Hinom.");
    b->dados[NEEMIAS].capitulos[11].versos[31] = wxT("Os filhos de Benjamim também habitaram desde Geba em diante, em Micmás e Aíja, em Betel e seus arrabaldes,");
    b->dados[NEEMIAS].capitulos[11].versos[32] = wxT("em Anatote, em Nobe, em Ananias,");
    b->dados[NEEMIAS].capitulos[11].versos[33] = wxT("em Hazor, em Ramá, em Gitaim,");
    b->dados[NEEMIAS].capitulos[11].versos[34] = wxT("em Hadide, em Zeboim, em Nebalate,");
    b->dados[NEEMIAS].capitulos[11].versos[35] = wxT("em Lode, e em Ono, vale dos artífices.");
    b->dados[NEEMIAS].capitulos[11].versos[36] = wxT("E dos levitas que habitavam em Judá, algumas turmas foram unidas a Benjamim.");

    b->dados[NEEMIAS].capitulos[12].versos[1] = wxT("Ora, estes são os sacerdotes e os levitas que subiram com Zorobabel, filho de Sealtiel, e com Jesuá: Seraías, Jeremias, Esdras,");
    b->dados[NEEMIAS].capitulos[12].versos[2] = wxT("Amarias, Maluque, Hatus,");
    b->dados[NEEMIAS].capitulos[12].versos[3] = wxT("Ido, Ginetói, Abias,");
    b->dados[NEEMIAS].capitulos[12].versos[4] = wxT("Secanias, Reum, Meremote,");
    b->dados[NEEMIAS].capitulos[12].versos[5] = wxT("Miamim, Maadias, Bilga,");
    b->dados[NEEMIAS].capitulos[12].versos[6] = wxT("Semaías, Joiaribe, Jedaías,");
    b->dados[NEEMIAS].capitulos[12].versos[7] = wxT("Salu, Amoque, Hilquias e Jedaías; estes foram os chefes dos sacerdotes e de seus irmãos, nos dias de Jesuá.");
    b->dados[NEEMIAS].capitulos[12].versos[8] = wxT("E os levitas: Jesuá, Binuí, Cadmiel, Serebias, Judá, Matanias; este e seus irmãos dirigiam os louvores.");
    b->dados[NEEMIAS].capitulos[12].versos[9] = wxT("E Baquebuquias e Uni, seus irmãos, estavam defronte deles segundo os seus cargos.");
    b->dados[NEEMIAS].capitulos[12].versos[10] = wxT("Jesuá foi pai de Joiaquim, Joiaquim de Eliasibe, Eliasibe de Joiada,");
    b->dados[NEEMIAS].capitulos[12].versos[11] = wxT("Joiada de Jonatã, e Jonatã de Jadua.");
    b->dados[NEEMIAS].capitulos[12].versos[12] = wxT("E nos dias de Joiaquim foram sacerdotes, chefes das casas paternas: por Seraías, Meraías; por Jeremias, Hananias;");
    b->dados[NEEMIAS].capitulos[12].versos[13] = wxT("por Esdras, Mesulão; por Amarias, Jeoanã;");
    b->dados[NEEMIAS].capitulos[12].versos[14] = wxT("por Malúqui, Jonatã; por Sebanias, José;");
    b->dados[NEEMIAS].capitulos[12].versos[15] = wxT("por Harim, Adná; por Meraiote, Helcai;");
    b->dados[NEEMIAS].capitulos[12].versos[16] = wxT("por Ido, Zacarias; por Gineton, Mesulão;");
    b->dados[NEEMIAS].capitulos[12].versos[17] = wxT("por Abias, Zicri; por Miniamim, por Moadias, Piltai;");
    b->dados[NEEMIAS].capitulos[12].versos[18] = wxT("por Bilga, Samua; por Semaías, Jeonatã;");
    b->dados[NEEMIAS].capitulos[12].versos[19] = wxT("por Joiaribe, Matenai; por Jedaías, Uzi;");
    b->dados[NEEMIAS].capitulos[12].versos[20] = wxT("por Salai, Calai; por Amoque, Eber;");
    b->dados[NEEMIAS].capitulos[12].versos[21] = wxT("por Hilquias, Hasabias; por Jedaías, Netanel.");
    b->dados[NEEMIAS].capitulos[12].versos[22] = wxT("Nos dias de Eliasibe, Joiada, Joanã e Jadua foram inscritos, dos levitas, os chefes das casas paternas; e assim também os dos sacerdotes, no reinado de Dário, o persa.");
    b->dados[NEEMIAS].capitulos[12].versos[23] = wxT("Os filhos de Levi, chefes de casas paternas, foram inscritos no livro das crônicas, até os dias de Joanã, filho de Eliasibe.");
    b->dados[NEEMIAS].capitulos[12].versos[24] = wxT("Foram, pois, os chefes dos levitas: Hasabias, Serebias, Jesuá, filho de Cadmiel, e seus irmãos que ficavam defronte deles, turma contra turma, para louvarem e darem graças, segundo a ordem de Davi, homem de Deus.");
    b->dados[NEEMIAS].capitulos[12].versos[25] = wxT("Matanias, Baquebuquias, Obadias, Mesulão, Talmom, e Acube eram porteiros, e faziam a guarda junto aos celeiros das portas.");
    b->dados[NEEMIAS].capitulos[12].versos[26] = wxT("Estes viveram nos dias de Joiaquim, filho de Jesuá, filho de Jozadaque, como também nos dias de Neemias, o governador, e do sacerdote Esdras, o escriba.");
    b->dados[NEEMIAS].capitulos[12].versos[27] = wxT("Ora, na dedicação dos muros de Jerusalém buscaram os levitas de todos os lugares, para os trazerem a Jerusalém, a fim de celebrarem a dedicação com alegria e com ações de graças, e com canto, címbalos, alaúdes e harpas.");
    b->dados[NEEMIAS].capitulos[12].versos[28] = wxT("Ajuntaram-se os filhos dos cantores, tanto da campina dos arredores de Jerusalém, como das aldeias do netofatitas;");
    b->dados[NEEMIAS].capitulos[12].versos[29] = wxT("como também de Bete-Gilgal, e dos campos de Geba e Azmavete; pois os cantores tinham edificado para si aldeias ao redor de Jerusalém.");
    b->dados[NEEMIAS].capitulos[12].versos[30] = wxT("E os sacerdotes e os levitas se purificaram, e purificaram o povo, as portas e o muro.");
    b->dados[NEEMIAS].capitulos[12].versos[31] = wxT("Então fiz subir os príncipes de Judá sobre o muro, e constituí duas grandes companhias para darem graças e andarem em procissão, uma das quais foi para a direita sobre o muro, em direção à porta do monturo;");
    b->dados[NEEMIAS].capitulos[12].versos[32] = wxT("e após ela seguiam Hosaías, e a metade dos príncipes de Judá,");
    b->dados[NEEMIAS].capitulos[12].versos[33] = wxT("e Azarias, Esdras, Mesulão,");
    b->dados[NEEMIAS].capitulos[12].versos[34] = wxT("Judá, Benjamim, Semaías, e Jeremias;");
    b->dados[NEEMIAS].capitulos[12].versos[35] = wxT("e dos filhos dos sacerdotes, levando trombetas, Zacarias, filho de Jonatã, filho de Semaías, filho de Matanias, filho de Micaías, filho de Zacur, filho de Asafe.");
    b->dados[NEEMIAS].capitulos[12].versos[36] = wxT("e seus irmãos, Semaías, Azarel, Milalai, Gilalai, Maai, Netanel, Judá e Hanâni, com os instrumento musicais de Davi, homem de Deus; e Esdras, o escriba, ia adiante deles.");
    b->dados[NEEMIAS].capitulos[12].versos[37] = wxT("À entrada da porta da fonte subiram diretamente as escadas da cidade de Davi onde começa a subida do muro, acima da casa de Davi, até a porta das águas a leste.");
    b->dados[NEEMIAS].capitulos[12].versos[38] = wxT("A outra companhia dos que davam graças foi para a esquerda, seguindo-os eu com a metade do povo, sobre o muro, passando pela torre dos fornos até a muralha larga,");
    b->dados[NEEMIAS].capitulos[12].versos[39] = wxT("e seguindo por cima da porta de Efraim, e da porta velha, e da porta dos peixes, e pela torre de Hananel, e a torre dos Cem até a porta das ovelhas; e pararam à porta da guarda.");
    b->dados[NEEMIAS].capitulos[12].versos[40] = wxT("Assim as duas companhias dos que davam graças pararam na casa de Deus, como também eu e a metade dos magistrados que estavam comigo,");
    b->dados[NEEMIAS].capitulos[12].versos[41] = wxT("e os sacerdotes Eliaquim, Maaséias, Miniamim, Micaías, Elioenai, Zacarias e Hananias, com trombetas,");
    b->dados[NEEMIAS].capitulos[12].versos[42] = wxT("com também Maaséias, Semaías, Eleazar, Uzi, Jeoanã, Malquias, Elão, e Ézer; e os cantores cantavam, tendo Jezraías por dirigente.");
    b->dados[NEEMIAS].capitulos[12].versos[43] = wxT("Naquele dia ofereceram grandes sacrifícios, e se alegraram, pois Deus lhes dera motivo de grande alegria; também as mulheres e as crianças se alegraram, de modo que o júbilo de Jerusalém se fez ouvir longe.");
    b->dados[NEEMIAS].capitulos[12].versos[44] = wxT("No mesmo dia foram nomeados homens sobre as câmaras do tesouro para as ofertas alçadas, as primícias e os dízimos, para nelas recolherem, dos campos, das cidades, os quinhões designados pela lei para os sacerdotes e para os levitas; pois Judá se alegrava por estarem os sacerdotes e os levitas no seu posto,");
    b->dados[NEEMIAS].capitulos[12].versos[45] = wxT("observando os preceitos do seu Deus, e os da purificação, como também o fizeram os cantores e porteiros, conforme a ordem de Davi e de seu filho Salomão.");
    b->dados[NEEMIAS].capitulos[12].versos[46] = wxT("Pois desde a antigüidade, já nos dias de Davi e de Asafe, havia um chefe dos cantores, e havia cânticos de louvor e de ação de graça a Deus.");
    b->dados[NEEMIAS].capitulos[12].versos[47] = wxT("Pelo que todo o Israel, nos dias de Zorobabel e nos dias de Neemias, dava aos cantores e aos porteiros as suas porções destinadas aos levitas, e os levitas separavam as porções destinadas aos filhos de Arão.");

    b->dados[NEEMIAS].capitulos[13].versos[1] = wxT("Naquele dia leu-se o livro de Moisés, na presença do povo, e achou-se escrito nele que os amonitas e os moabitas não entrassem jamais na assembléias de Deus;");
    b->dados[NEEMIAS].capitulos[13].versos[2] = wxT("porquanto não tinham saído ao encontro dos filhos de Israel com pão e água, mas contra eles assalariaram Balaão para os amaldiçoar; contudo o nosso Deus converteu a maldição em benção.");
    b->dados[NEEMIAS].capitulos[13].versos[3] = wxT("Ouvindo eles esta lei, apartaram de Israel toda a multidão mista.");
    b->dados[NEEMIAS].capitulos[13].versos[4] = wxT("Ora, antes disto Eliasibe, sacerdote, encarregado das câmaras da casa de nosso Deus, se aparentara com Tobias,");
    b->dados[NEEMIAS].capitulos[13].versos[5] = wxT("e lhe fizera uma câmara grande, onde dantes se recolhiam as ofertas de cereais, o incenso, os utensílios, os dízimos dos cereais, do mosto e do azeite, que eram dados por ordenança aos levitas, aos cantores e aos porteiros, como também as ofertas alçadas para os sacerdotes.");
    b->dados[NEEMIAS].capitulos[13].versos[6] = wxT("Mas durante todo este tempo não estava eu em Jerusalém, porque no ano trinta e dois de Artaxerxes, rei da Babilônia, fui ter com o rei; mas a cabo de alguns dias pedi licença ao rei,");
    b->dados[NEEMIAS].capitulos[13].versos[7] = wxT("e vim a Jerusalém; e soube do mal que Eliasibe fizera em servir a Tobias, preparando-lhe uma câmara nos átrios da casa de Deus.");
    b->dados[NEEMIAS].capitulos[13].versos[8] = wxT("Isso muito me desagradou; pelo que lancei todos os móveis da casa de Tobias fora da câmara.");
    b->dados[NEEMIAS].capitulos[13].versos[9] = wxT("Então, por minha ordem purificaram as câmaras; e tornei a trazer para ali os utensílios da casa de Deus, juntamente com as ofertas de cereais e o incenso.");
    b->dados[NEEMIAS].capitulos[13].versos[10] = wxT("Também soube que os quinhões dos levitas não se lhes davam, de maneira que os levitas e os cantores, que faziam o serviço, tinham fugido cada um para o seu campo.");
    b->dados[NEEMIAS].capitulos[13].versos[11] = wxT("Então contendi com os magistrados e disse: Por que se abandonou a casa de Deus? Eu, pois, ajuntei os levitas e os cantores e os restaurei no seu posto.");
    b->dados[NEEMIAS].capitulos[13].versos[12] = wxT("Então todo o Judá trouxe para os celeiros os dízimos dos cereais, do mosto e do azeite.");
    b->dados[NEEMIAS].capitulos[13].versos[13] = wxT("E por tesoureiros pus sobre os celeiros Selemias, o sacerdote, e Zadoque, o escrivão, e Pedaías, dentre os levitas, e como ajudante deles Hanã, filho de Zacur, filho de Matanias, porque foram achados fiéis; e se lhes encarregou de fazerem a distribuição entre seus irmãos.");
    b->dados[NEEMIAS].capitulos[13].versos[14] = wxT("Por isto, Deus meu, lembra-te de mim, e não risques as beneficências que eu tenho feito para a casa do meu Deus e para o serviço dela.");
    b->dados[NEEMIAS].capitulos[13].versos[15] = wxT("Naqueles dias vi em Judá homens que pisavam lugares no sábado, e traziam molhos, que carregavam sobre jumentos; vi também vinho, uvas e figos, e toda sorte de cargas, que eles traziam a Jerusalém no dia de sábado; e protestei contra eles quanto ao dia em que estavam vendendo mantimentos.");
    b->dados[NEEMIAS].capitulos[13].versos[16] = wxT("E em Jerusalém habitavam homens de Tiro, os quais traziam peixes e toda sorte de mercadorias, que vendiam no sábado aos filhos de Judá, e em Jerusalém.");
    b->dados[NEEMIAS].capitulos[13].versos[17] = wxT("Então contendi com os nobres de Judá, e lhes disse: Que mal é este que fazeis, profanando o dia de sábado?");
    b->dados[NEEMIAS].capitulos[13].versos[18] = wxT("Porventura não fizeram vossos pais assim, e não trouxe nosso Deus todo este mal sobre nós e sobre esta cidade? Contudo vós ainda aumentais a ira sobre Israel, profanando o sábado.");
    b->dados[NEEMIAS].capitulos[13].versos[19] = wxT("E sucedeu que, ao começar a fazer-se escuro nas portas de Jerusalém, antes do sábado, eu ordenei que elas fossem fechadas, e mandei que não as abrissem até passar o sábado e pus às portas alguns de meus moços, para que nenhuma carga entrasse no dia de sábado.");
    b->dados[NEEMIAS].capitulos[13].versos[20] = wxT("Então os negociantes e os vendedores de toda sorte de mercadorias passaram a noite fora de Jerusalém, uma ou duas vezes.");
    b->dados[NEEMIAS].capitulos[13].versos[21] = wxT("Protestei, pois, contra eles, dizendo-lhes: Por que passais a noite defronte do muro? Se outra vez o fizerdes, hei de lançar mão em vós. Daquele tempo em diante não vieram no sábado.");
    b->dados[NEEMIAS].capitulos[13].versos[22] = wxT("Também ordenei aos levitas que se purificassem, e viessem guardar as portas, para santificar o sábado. Nisso também, Deus meu, lembra-te de mim, e perdoa-me segundo a abundância da tua misericórdia.");
    b->dados[NEEMIAS].capitulos[13].versos[23] = wxT("Vi também naqueles dias judeus que tinham casado com mulheres asdoditas, amonitas, e moabitas;");
    b->dados[NEEMIAS].capitulos[13].versos[24] = wxT("e seus filhos falavam no meio asdodita, e não podiam falar judaico, senão segundo a língua de seu povo.");
    b->dados[NEEMIAS].capitulos[13].versos[25] = wxT("Contendi com eles, e os amaldiçoei; espanquei alguns deles e, arrancando-lhes os cabelos, os fiz jurar por Deus, e lhes disse: Não darei vossas filhas a seus filhos, e não tomareis suas filhas para vossos filhos, nem para vós mesmos.");
    b->dados[NEEMIAS].capitulos[13].versos[26] = wxT("Não pecou nisso Salomão, rei de Israel? Entre muitas nações não havia rei semelhante a ele, e ele era amado de seu Deus, e Deus o constituiu rei sobre todo o Israel. Contudo mesmo a ele as mulheres estrangeiras o fizeram pecar.");
    b->dados[NEEMIAS].capitulos[13].versos[27] = wxT("E dar-vos-íamos nós ouvidos, para fazermos todo este grande mal, esta infidelidade contra o nosso Deus, casando com mulheres estrangeiras?");
    b->dados[NEEMIAS].capitulos[13].versos[28] = wxT("Também um dos filhos de Joiada, filho do sumo sacerdote Eliasibe, era genro de Sambalate, o horonita, pelo que o afugentei de mim.");
    b->dados[NEEMIAS].capitulos[13].versos[29] = wxT("(falta este versículo)");
    b->dados[NEEMIAS].capitulos[13].versos[30] = wxT("Assim os purifiquei de tudo que era estrangeiro, e determinei os cargos para os sacerdotes e para os levitas, cada um na sua função;");
    b->dados[NEEMIAS].capitulos[13].versos[31] = wxT("como também o que diz respeito à oferta da lenha em tempos determinados, e bem assim às primícias. Lembra-te de mim, Deus meu, para o meu bem.");

}
